/*
 * Phase 3: Enhanced Hexagon context switching implementation
 * Supports full register context save/restore
 */

#include <zephyr/toolchain.h>
#include <zephyr/linker/sections.h>
#include <zephyr/arch/hexagon/thread.h>

/* Enhanced context structure offsets - to be generated by offsets.h */
#define HEXAGON_CONTEXT_R16_OFFSET  0x00
#define HEXAGON_CONTEXT_R17_OFFSET  0x04
#define HEXAGON_CONTEXT_R18_OFFSET  0x08
#define HEXAGON_CONTEXT_R19_OFFSET  0x0C
#define HEXAGON_CONTEXT_R20_OFFSET  0x10
#define HEXAGON_CONTEXT_R21_OFFSET  0x14
#define HEXAGON_CONTEXT_R22_OFFSET  0x18
#define HEXAGON_CONTEXT_R23_OFFSET  0x1C
#define HEXAGON_CONTEXT_R24_OFFSET  0x20
#define HEXAGON_CONTEXT_R25_OFFSET  0x24
#define HEXAGON_CONTEXT_R26_OFFSET  0x28
#define HEXAGON_CONTEXT_R27_OFFSET  0x2C
#define HEXAGON_CONTEXT_R28_OFFSET  0x30
#define HEXAGON_CONTEXT_R29_OFFSET  0x34
#define HEXAGON_CONTEXT_R30_OFFSET  0x38
#define HEXAGON_CONTEXT_R31_OFFSET  0x3C
#define HEXAGON_CONTEXT_USR_OFFSET  0x40
#define HEXAGON_CONTEXT_UGP_OFFSET  0x44
#define HEXAGON_CONTEXT_LC0_OFFSET  0x48
#define HEXAGON_CONTEXT_LC1_OFFSET  0x4C
#define HEXAGON_CONTEXT_SA0_OFFSET  0x50
#define HEXAGON_CONTEXT_SA1_OFFSET  0x54
#define HEXAGON_CONTEXT_P3_0_OFFSET 0x58
#define HEXAGON_CONTEXT_G0_OFFSET   0x5C
#define HEXAGON_CONTEXT_G1_OFFSET   0x60
#define HEXAGON_CONTEXT_G2_OFFSET   0x64
#define HEXAGON_CONTEXT_G3_OFFSET   0x68

#define HEXAGON_CONTEXT_SIZE        0x6C

GTEXT(arch_switch_enhanced)

/*
 * arch_switch_enhanced - Enhanced cooperative context switch
 * 
 * r0 = new thread to switch to
 * r1 = old thread to switch from (out parameter)
 * 
 * This implements the full Phase 3 context switching with complete
 * register save/restore including control and VM registers.
 */
SECTION_FUNC(TEXT, arch_switch_enhanced)
    /* Allocate stack frame for enhanced context save */
    allocframe(#HEXAGON_CONTEXT_SIZE)
    
    /* Save callee-saved registers */
    {
        memd(r29+#HEXAGON_CONTEXT_R16_OFFSET) = r17:16
        memd(r29+#HEXAGON_CONTEXT_R18_OFFSET) = r19:18
    }
    {
        memd(r29+#HEXAGON_CONTEXT_R20_OFFSET) = r21:20
        memd(r29+#HEXAGON_CONTEXT_R22_OFFSET) = r23:22
    }
    {
        memd(r29+#HEXAGON_CONTEXT_R24_OFFSET) = r25:24
        memd(r29+#HEXAGON_CONTEXT_R26_OFFSET) = r27:26
    }
    {
        memw(r29+#HEXAGON_CONTEXT_R28_OFFSET) = r28
        memw(r29+#HEXAGON_CONTEXT_R29_OFFSET) = r29
    }
    {
        memw(r29+#HEXAGON_CONTEXT_R30_OFFSET) = r30
        memw(r29+#HEXAGON_CONTEXT_R31_OFFSET) = r31
    }
    
    /* Save control registers */
    {
        r2 = usr
        memw(r29+#HEXAGON_CONTEXT_USR_OFFSET) = r2
    }
    {
        r2 = ugp
        memw(r29+#HEXAGON_CONTEXT_UGP_OFFSET) = r2
    }
    
    /* Save loop registers */
    {
        r2 = lc0
        memw(r29+#HEXAGON_CONTEXT_LC0_OFFSET) = r2
    }
    {
        r2 = lc1
        memw(r29+#HEXAGON_CONTEXT_LC1_OFFSET) = r2
    }
    {
        r2 = sa0
        memw(r29+#HEXAGON_CONTEXT_SA0_OFFSET) = r2
    }
    {
        r2 = sa1
        memw(r29+#HEXAGON_CONTEXT_SA1_OFFSET) = r2
    }
    
    /* Save predicate registers */
    {
        r2 = p3:0
        memb(r29+#HEXAGON_CONTEXT_P3_0_OFFSET) = r2
    }
    
    /* Save VM guest registers */
    {
        r2 = g0
        memw(r29+#HEXAGON_CONTEXT_G0_OFFSET) = r2
    }
    {
        r2 = g1
        memw(r29+#HEXAGON_CONTEXT_G1_OFFSET) = r2
    }
    {
        r2 = g2
        memw(r29+#HEXAGON_CONTEXT_G2_OFFSET) = r2
    }
    {
        r2 = g3
        memw(r29+#HEXAGON_CONTEXT_G3_OFFSET) = r2
    }
    
    /* Save current stack pointer to old thread's enhanced context */
    /* Assuming thread->arch.context is at offset 0 in _thread_arch */
    {
        memw(r1) = r29  /* Save stack pointer as context pointer */
    }
    
    /* Load new thread's context pointer */
    {
        r29 = r0  /* New thread's context stack pointer */
    }
    
    /* Restore VM guest registers */
    {
        r2 = memw(r29+#HEXAGON_CONTEXT_G0_OFFSET)
        g0 = r2
    }
    {
        r2 = memw(r29+#HEXAGON_CONTEXT_G1_OFFSET)
        g1 = r2
    }
    {
        r2 = memw(r29+#HEXAGON_CONTEXT_G2_OFFSET)
        g2 = r2
    }
    {
        r2 = memw(r29+#HEXAGON_CONTEXT_G3_OFFSET)
        g3 = r2
    }
    
    /* Restore predicate registers */
    {
        r2 = memb(r29+#HEXAGON_CONTEXT_P3_0_OFFSET)
        p3:0 = r2
    }
    
    /* Restore loop registers */
    {
        r2 = memw(r29+#HEXAGON_CONTEXT_SA1_OFFSET)
        sa1 = r2
    }
    {
        r2 = memw(r29+#HEXAGON_CONTEXT_SA0_OFFSET)
        sa0 = r2
    }
    {
        r2 = memw(r29+#HEXAGON_CONTEXT_LC1_OFFSET)
        lc1 = r2
    }
    {
        r2 = memw(r29+#HEXAGON_CONTEXT_LC0_OFFSET)
        lc0 = r2
    }
    
    /* Restore control registers */
    {
        r2 = memw(r29+#HEXAGON_CONTEXT_UGP_OFFSET)
        ugp = r2
    }
    {
        r2 = memw(r29+#HEXAGON_CONTEXT_USR_OFFSET)
        usr = r2
    }
    
    /* Restore callee-saved registers */
    {
        r31 = memw(r29+#HEXAGON_CONTEXT_R31_OFFSET)
        r30 = memw(r29+#HEXAGON_CONTEXT_R30_OFFSET)
    }
    {
        r28 = memw(r29+#HEXAGON_CONTEXT_R28_OFFSET)
        /* r29 will be restored by deallocframe */
    }
    {
        r27:26 = memd(r29+#HEXAGON_CONTEXT_R26_OFFSET)
        r25:24 = memd(r29+#HEXAGON_CONTEXT_R24_OFFSET)
    }
    {
        r23:22 = memd(r29+#HEXAGON_CONTEXT_R22_OFFSET)
        r21:20 = memd(r29+#HEXAGON_CONTEXT_R20_OFFSET)
    }
    {
        r19:18 = memd(r29+#HEXAGON_CONTEXT_R18_OFFSET)
        r17:16 = memd(r29+#HEXAGON_CONTEXT_R16_OFFSET)
    }
    
    /* Return to new thread context */
    {
        dealloc_return
    }